/* Suggested markup: <div class="uiwiki-quiet-signal-topography" tabindex="0"><span>Quiet Signal Topography</span></div> */
.uiwiki-quiet-signal-topography {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-quiet-signal-topography > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #f5c9d4;
  animation: quiet_signal_topography 1.8s ease-in-out infinite alternate;
}
.uiwiki-quiet-signal-topography:hover,
.uiwiki-quiet-signal-topography:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes quiet_signal_topography {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-quiet-signal-topography, .uiwiki-quiet-signal-topography > span { animation: none; transition: none; }
}
